import{_ as l,C as E,o as e,c as s,a5 as a,b as i,w as n,a as o,E as g,a4 as A}from"./chunks/framework.gGRxziV4.js";const m=JSON.parse('{"title":"LangChain实战与工具设计","description":"","frontmatter":{},"headers":[],"relativePath":"01-Harness工程核心原则/05-验证、工具与优化.md","filePath":"01-Harness工程核心原则/05-验证、工具与优化.md","lastUpdated":1774181700000}'),d={name:"01-Harness工程核心原则/05-验证、工具与优化.md"};function h(B,t,p,_,c,f){const r=E("Mermaid");return e(),s("div",null,[t[1]||(t[1]=a('<h1 id="langchain实战与工具设计" tabindex="-1">LangChain实战与工具设计 <a class="header-anchor" href="#langchain实战与工具设计" aria-label="Permalink to &quot;LangChain实战与工具设计&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 1 模块的第 5 章。</p></blockquote><p>LangChain 通过调优 Harness 让 Deep Agents 跑分从 52.8 提升到 66.5，从榜单第 30 开外一路进到前五——不改变模型基座，只调 Harness。</p><hr><h2 id="诊断-trace-即反馈" tabindex="-1">诊断：Trace 即反馈 <a class="header-anchor" href="#诊断-trace-即反馈" aria-label="Permalink to &quot;诊断：Trace 即反馈&quot;">​</a></h2><p>Agent 跑偏、报错、超时之后，留下的是成千上万行运行轨迹。LangChain 把&quot;读日志找问题&quot;做成了 Trace Analyzer Skill——从 LangSmith 把所有运行轨迹拉下来，按批次切分启动多个分析子 Agent 并行跑，所有结论汇总成改进建议。</p><p>关键约束：改动必须是通用的。对特定任务过度拟合的修改可能让其他题目的表现退步。Trace 是整个改进闭环的核心信号。</p><hr><h2 id="四条有效改进" tabindex="-1">四条有效改进 <a class="header-anchor" href="#四条有效改进" aria-label="Permalink to &quot;四条有效改进&quot;">​</a></h2>',9)),(e(),i(A,null,{default:n(()=>[g(r,{id:"mermaid-25",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5BTrace%20%E6%95%B0%E6%8D%AE%5D%20--%3E%20B%5BTrace%20Analyzer%20Skill%5D%0A%20%20%20%20B%20--%3E%20C%5B%E5%B9%B6%E8%A1%8C%E5%88%86%E6%9E%90%E5%AD%90%20Agent%5D%0A%20%20%20%20C%20--%3E%20D%5B%E7%BB%93%E6%9E%84%E5%8C%96%E6%94%B9%E8%BF%9B%E5%BB%BA%E8%AE%AE%5D%0A%20%20%20%20D%20--%3E%20E%5B%E5%BC%BA%E5%88%B6%E9%AA%8C%E8%AF%81%3Cbr%2F%3E%E8%A7%84%E5%88%92%E2%86%92%E6%9E%84%E5%BB%BA%E2%86%92%E9%AA%8C%E8%AF%81%E2%86%92%E4%BF%AE%E5%A4%8D%5D%0A%20%20%20%20D%20--%3E%20F%5B%E4%B8%8A%E4%B8%8B%E6%96%87%E6%B3%A8%E5%85%A5%3Cbr%2F%3E%E7%8E%AF%E5%A2%83%E5%9C%B0%E5%9B%BE%2B%E8%AF%84%E4%BC%B0%E5%A3%B0%E6%98%8E%2B%E6%97%B6%E9%97%B4%E9%A2%84%E7%AE%97%5D%0A%20%20%20%20D%20--%3E%20G%5B%E5%BE%AA%E7%8E%AF%E6%8E%A2%E6%B5%8B%3Cbr%2F%3E%E7%BC%96%E8%BE%91%E6%AC%A1%E6%95%B0%3E%E9%98%88%E5%80%BC%E2%86%92%E6%B3%A8%E5%85%A5%E5%8F%8D%E6%80%9D%5D%0A%20%20%20%20D%20--%3E%20H%5B%E7%AE%97%E5%8A%9B%E5%88%86%E9%85%8D%3Cbr%2F%3E%E8%A7%84%E5%88%92X-High%2F%E5%AE%9E%E7%8E%B0High%2F%E9%AA%8C%E8%AF%81X-High%5D%0A%20%20%20%20E%20--%3E%20I%5B%E8%B7%91%E5%88%86%E6%8F%90%E5%8D%87%2052.8%E2%86%9266.5%5D%0A%20%20%20%20F%20--%3E%20I%0A%20%20%20%20G%20--%3E%20I%0A%20%20%20%20H%20--%3E%20I%0A"})]),fallback:n(()=>[...t[0]||(t[0]=[o(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=a('<blockquote><p>💡 <strong>图解：</strong> LangChain 不换模型、不改架构，只调 Harness 就推了 13.7 分——Harness 是逼近模型能力上限的杠杆。</p></blockquote><p><strong>强制验证</strong>：Agent 最常见的失败模式是写完代码直接宣告完成没运行测试。两道防线——提示词层面的规划→构建→验证→修复四步框架，系统层面的完结前检查中间件强制拦截验证。</p><p><strong>上下文注入</strong>：Agent 一启动系统自动扫描目录结构注入环境地图；明确声明&quot;你的产出会被自动化测试评估&quot;；接近截止时间时注入时间预算提醒。不要让 Agent 自己去发现和组装运行条件，Harness 要主动递给模型。</p><p><strong>循环探测</strong>：Doom Loops——Agent 在同一文件上连续修改超过十次但思路没变。循环探测中间件记录编辑次数，超过阈值注入反思提示。这是针对当下模型缺陷的工程护栏，随着模型进化会变得多余。</p><p><strong>算力分配</strong>：全程 X-High 推理反而更差。分段式分配——规划阶段 X-High、实现阶段 High、验证阶段 X-High。推理加薪策略把分数推到 66.5%。</p><hr><h2 id="工具设计哲学" tabindex="-1">工具设计哲学 <a class="header-anchor" href="#工具设计哲学" aria-label="Permalink to &quot;工具设计哲学&quot;">​</a></h2><p>Seeing Like an Agent——从 Agent 的角度观察，盯着调用频率、调用时机、输出质量。</p><p><strong>ask_user_question 的三次迭代</strong>：第一次塞进 Exit Plan 工具（意图混淆失败），第二次改输出格式（格式不稳定失败），第三次专门建工具（成功——语义对应、Schema 约束、阻塞机制）。</p><p>三条经验：一个工具一种意图、Schema 约束而非格式约定、工具要让模型愿意用。</p><p><strong>工具迭代</strong>：模型变强后旧工具变枷锁。todo_write 升级为 task——从单 Agent 清单变成多 Agent 共享协作面板。</p><p><strong>渐进式披露</strong>：Guide 子代理按需读取文档只返回精确答案，避免主模型认知膨胀。</p><hr><h2 id="⚠️-常见错误" tabindex="-1">⚠️ 常见错误 <a class="header-anchor" href="#⚠️-常见错误" aria-label="Permalink to &quot;⚠️ 常见错误&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">❌ 错误做法</th><th style="text-align:left;">✅ 正确做法</th><th style="text-align:left;">为什么</th></tr></thead><tbody><tr><td style="text-align:left;">Agent 写完代码读一遍自己写的，觉得逻辑自洽就宣告完成</td><td style="text-align:left;">强制要求运行测试，结果对照原始任务要求而非自己的代码</td><td style="text-align:left;">大模型在语言层面可自洽，实际运行完全可能出错——只有测试给出真实反馈信号</td></tr><tr><td style="text-align:left;">让 Agent 自行探索目录结构、安装环境信息</td><td style="text-align:left;">系统自动扫描目录注入环境地图，Agent 拿到的是整理好的运行地图</td><td style="text-align:left;">Agent 自行发现上下文的过程本身是高错误率环节——路径理解错误、文件层级判断失误都会让任务跑偏</td></tr><tr><td style="text-align:left;">不告诉 Agent 评估标准是什么</td><td style="text-align:left;">在系统提示中明确声明&quot;你的产出会被自动化测试评估&quot;</td><td style="text-align:left;">模型不知道什么叫可测试性，把评估标准提前显性化才能避免只在理想情况下通过</td></tr><tr><td style="text-align:left;">Agent 在同一文件上反复修改超过十次思路不变</td><td style="text-align:left;">循环探测中间件记录编辑次数，超过阈值注入反思提示</td><td style="text-align:left;">Doom Loops：模型卡在局部最优出不来，不断消耗算力却无法推进——需要强制跳出重新审视整体方案</td></tr><tr><td style="text-align:left;">全程用最高推理等级</td><td style="text-align:left;">分段式算力分配——规划 X-High、实现 High、验证 X-High</td><td style="text-align:left;">全程 X-High 推理反而更差，合理分配算力才能在关键环节集中火力</td></tr></tbody></table><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>LangChain 用 Harness 提升 13.7 分（52.8→66.5）</li><li>四条改进：强制验证、上下文注入、循环探测、算力分配</li><li>Seeing Like an Agent：一个工具一种意图，Schema 约束</li><li>模型能力决定上限，Harness 决定逼近上限多少</li></ul><hr><p><strong>上一章</strong>: <a href="./04-Harness即操作系统.html">Harness即操作系统</a> | <strong>下一章</strong>: <a href="./06-争论与未来.html">争论与未来</a></p>',20))])}const x=l(d,[["render",h]]);export{m as __pageData,x as default};
